import { proxyActivities, sleep } from '@temporalio/workflow';

export interface ReminderInput {
  message: string;
  delaySeconds: number;
}

const { Notify } = proxyActivities<{ Notify(message: string): Promise<string> }>({
  startToCloseTimeout: '1 minute',
});

export async function ReminderWorkflow(input: ReminderInput): Promise<string> {
  await sleep(input.delaySeconds * 1000);
  return Notify(input.message);
}

import fs from 'node:fs';

export async function Notify(message: string): Promise<string> {
  const line = `Notified: ${message}`;
  fs.mkdirSync('/workspace', { recursive: true });
  fs.appendFileSync('/workspace/reminder.log', `${line}\n`);
  return line;
}

import { NativeConnection, Worker } from '@temporalio/worker';
import * as activities from './activities';

function requireEnv(name: string): string {
  const value = process.env[name];
  if (!value) {
    throw new Error(`${name} is required`);
  }
  return value;
}

async function runWorker(): Promise<void> {
  const connection = await NativeConnection.connect({
    address: requireEnv('TEMPORAL_ADDRESS'),
    tls: true,
    apiKey: requireEnv('TEMPORAL_API_KEY'),
  });

  const worker = await Worker.create({
    connection,
    namespace: requireEnv('TEMPORAL_NAMESPACE'),
    taskQueue: 'reminder-ts',
    workflowsPath: require.resolve('./workflows'),
    activities,
  });

  await worker.run();
}

runWorker().catch((error) => {
  console.error(error);
  process.exit(1);
});

import { Client, Connection } from '@temporalio/client';

function requireEnv(name: string): string {
  const value = process.env[name];
  if (!value) {
    throw new Error(`${name} is required`);
  }
  return value;
}

export async function runClient(): Promise<string> {
  const connection = await Connection.connect({
    address: requireEnv('TEMPORAL_ADDRESS'),
    tls: true,
    apiKey: requireEnv('TEMPORAL_API_KEY'),
  });

  const client = new Client({
    connection,
    namespace: requireEnv('TEMPORAL_NAMESPACE'),
  });

  const workflowId = `reminder-${requireEnv('ZEALT_RUN_ID')}`;

  const result = await client.workflow.execute('ReminderWorkflow', {
    taskQueue: 'reminder-ts',
    workflowId,
    args: [{ message: 'wake up', delaySeconds: 3 }],
  });

  return result;
}

if (require.main === module) {
  runClient()
    .then((result) => {
      console.log(result);
    })
    .catch((error) => {
      console.error(error);
      process.exit(1);
    });
}

import { spawn } from 'node:child_process';
import { runClient } from './client';

function wait(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

async function run(): Promise<void> {
  const workerProcess = spawn('ts-node', ['src/worker.ts'], {
    stdio: 'inherit',
  });

  workerProcess.on('exit', (code) => {
    if (code !== null && code !== 0) {
      console.error(`Worker exited with code ${code}`);
    }
  });

  await wait(1500);

  try {
    const result = await runClient();
    console.log(result);
  } finally {
    workerProcess.kill('SIGTERM');
  }
}

run().catch((error) => {
  console.error(error);
  process.exit(1);
});
